public String createShortLink(String originLink) {
    // ......

    String shortUri = generateSuffix(originLink);
    String shortLink = "nageoffer.com/" + shortUri;

    ShortLinkDO shortLinkDO = ShortLinkDO.builder()
            .shortUri(shortUri)
            .fullShortUrl(shortLink)
            .build();
    shortLinkMapper.insert(shortLinkDO);

    int hash32 = MurmurHash.hash32(shortLink);
    long mod = hash32 < 0 ? Integer.MAX_VALUE - (long) hash32 : hash32;

    // 获取布隆过滤器最新的数量
    int bloomFilterSize = Integer.parseInt(stringRedisTemplate.opsForValue().get("sharding-expansion:bloom_filter_size"));
    long idx = mod % bloomFilterSize;

    String bloomFilterCurrentIndex = stringRedisTemplate.opsForValue().get("sharding-expansion:bloom_filter_current_index");
    RBloomFilter<String> bloomFilter = redissonClient.getBloomFilter(String.format("sharding-expansion:short-link-create-bloom-filter-%s-%d", bloomFilterCurrentIndex, idx));
    bloomFilter.add(shortLink);

    String expansionFlag = stringRedisTemplate.opsForValue().get("sharding-expansion:expansion_flag");
    if (expansionFlag != null && expansionFlag.equals("true")) {
        idx = mod % calculateExpansionSize(bloomFilterSize);

        String expansionIdx = BloomFilterIdxUtil.reversal(bloomFilterCurrentIndex);
        RBloomFilter<String> expansionBloomFilter = redissonClient.getBloomFilter(String.format("sharding-expansion:short-link-create-bloom-filter-%s-%d", expansionIdx, idx));
        expansionBloomFilter.add(shortLink);
    }

    return shortLink;
}
